import{_ as a,o as r,c as t,a1 as o}from"./chunks/framework.BX4nIuL2.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/Fab/fabcovid19.md","filePath":"courses/fab-course/doc/Fab/fabcovid19.md"}'),i={name:"courses/fab-course/doc/Fab/fabcovid19.md"};function l(s,e,b,n,c,p){return r(),t("div",null,[...e[0]||(e[0]=[o('<h2 id="fablab-covid19-project" tabindex="-1">Fablab-Covid19 project <a class="header-anchor" href="#fablab-covid19-project" aria-label="Permalink to &quot;Fablab-Covid19 project&quot;">​</a></h2><p>Neil 在Fab Lab网络组织协作，进行防疫相关的项目讨论，设计，开发，项目分享；以下为链接：<a href="https://gitlab.fabcloud.org/pub/project/coronavirus/tracking" target="_blank" rel="noreferrer">Fab Lab-Covid 19</a></p><h2 id="shield" tabindex="-1">Shield <a class="header-anchor" href="#shield" aria-label="Permalink to &quot;Shield&quot;">​</a></h2><p>1.<a href="https://gitlab.cba.mit.edu/zfredin/quickshield" target="_blank" rel="noreferrer">framed face shield</a>：<a href="https://project-manus.mit.edu/fs-health" target="_blank" rel="noreferrer">发起团队：project manus from MIT</a>使用水刀，激光切割，3d打印等不同方式加工面罩，给波士顿当地的医护人员使用，售价2.79美元一个，同时开源设计方案 <img src="https://gitlab.com/picbed/bed/uploads/0bf86c973976759b703c60cfa67ee169/framed_face_shield.png" alt=""></p><p>2.<a href="https://gitlab.cba.mit.edu/alfonso/covid19-fast-kirishield" target="_blank" rel="noreferrer">frameless face shield</a> ，此处为CBA项目，无权限访问</p><p>3.<a href="https://tourlomousis.pages.cba.mit.edu/cvd-electrospinning/" target="_blank" rel="noreferrer">electrospun filter production</a>针对市场上过滤器不足的情况，Filippos Tourlomousis, Camron Blackburn, Jiri Zemanek, Zach Fredin and Neil Gershenfeld提出制造口罩过滤材料的方案：根据计算，如果全球所有Fab Lab一起工作，每个小时可以生产706000个口罩的过滤材料。<a href="https://gitlab.cba.mit.edu/camblackburn/filter_testing#fn2-7883" target="_blank" rel="noreferrer">目前在测试阶段</a>。 <img src="https://gitlab.com/picbed/bed/uploads/48037250ce2c333f83b89f41595c0952/framlessfaceshield.png" alt=""></p><p>4.<a href="https://gitlab.cba.mit.edu/camblackburn/filter_testing" target="_blank" rel="noreferrer">mask filter testing</a> ，过滤材料需要满足一些AST标准 [F2299]（<a href="https://www.astm.org/Standards/F2299.htm%EF%BC%89" target="_blank" rel="noreferrer">https://www.astm.org/Standards/F2299.htm）</a>, <a href="https://www.astm.org/Standards/F2101.htm" target="_blank" rel="noreferrer">F2101</a>,此处他们分享了对应的测试方式 <img src="https://gitlab.com/picbed/bed/uploads/90363b68086963b6a2bb7d0d798b2180/proposed_apparatus.jpg" alt=""></p><p>5.<a href="https://gitlab.cba.mit.edu/pub/coronavirus/pph-ppe" target="_blank" rel="noreferrer">positive pressure helmets</a> ，此处分享了使用<a href="https://www.mcmaster.com/8567K52/" target="_blank" rel="noreferrer">PET膜</a>去设计开发防护头盔的方式。 <img src="https://gitlab.com/picbed/bed/uploads/8bce23b182505ddff5e655541b9a8e9b/infant-cpap.jpg" alt=""></p><p>6.<a href="https://gitlab.cba.mit.edu/pub/coronavirus/minimal-ace2-binder" target="_blank" rel="noreferrer">minimal ACE2 binder</a>：此研究探讨了病毒侵入ACE2的情况,从<a href="https://docs.google.com/presentation/d/1pBbvAV8Oj_wA8ad5OImwPeQpZk1AJ8pxCPjtFxY5iXI/edit?usp=sharing" target="_blank" rel="noreferrer">背景</a><a href="https://docs.google.com/document/d/1fjair-MdOtAtdRhhaYCswoUKwD0mebEIs4ByrdhS4L8/edit?usp=sharing" target="_blank" rel="noreferrer">潜在方案</a>深入探讨；</p><p>7.<a href="https://gitlab.cba.mit.edu/pub/coronavirus/the-maski" target="_blank" rel="noreferrer">origami inspired mask design</a>,此处为CBA项目，无权限访问 <a href="https://gitlab.cba.mit.edu/zfredin/intubation-box" target="_blank" rel="noreferrer">intubation box</a> ,由于医生建议（太危险），他们做了外壳后停止研究，目前侧重研究隔离箱，目前在波士顿医学中心（Boston Medical Center）使用。这个方案使用的材料是 PETG，用<a href="https://www.zund.com/en" target="_blank" rel="noreferrer">zund</a>切割机加工 <img src="https://gitlab.com/picbed/bed/uploads/4f02ecd69bf7413f82c8e2e7e738bb15/isolatebox.png" alt=""></p><p>8.<a href="https://gitlab.fabcloud.org/AcademicMaslow/zlem-1-medical-face-shield" target="_blank" rel="noreferrer">Medical Face Shield</a>，<a href="https://vk.com/@kvantorium37-ivanovskii-kvantoriumnovatoriya-nachal-vypusk-zaschitnyh-ekr" target="_blank" rel="noreferrer">使用PET加工防护面具</a><img src="https://gitlab.com/picbed/bed/uploads/d60abb62aa24690f22d7be92ce955621/WX20201103-140014_2x.png" alt=""></p><p>9.<a href="https://gitlab.cba.mit.edu/zfredin/melt-blowing" target="_blank" rel="noreferrer">melt-blown polypropylene filter elements</a> ：此方案讲解的是基于Fab Lab的能力进行熔喷布的加工，此项目目前做了背景情况了解，暂未做实际开发</p><p><a href="https://gitlab.fabcloud.org/pub/project/coronavirus/tracking#projects-shared-by-the-network" target="_blank" rel="noreferrer">其他社会组织项目参考</a></p>',13)])])}const h=a(i,[["render",l]]);export{f as __pageData,h as default};
